/*

[!] Find (JetAll-head-content) to edit Open Graph and other Meta Tags

-------------------------
#   JetTheme Setting    #
-------------------------

<Variable name="tagline" description="Tagline" type="string" value=""/>
[!] Homepage tagline, ex: BlogName - Tagline

<Variable name="separator" description="Separator" type="string" value=" - "/>
[!] Title separator, ex : ( – ), ( | ), ( • )

<Variable name="description" description="Description" type="string" value=""/>
[!] Default meta description, recommended 155–160 characters

<Variable name="cover" description="Cover" type="string" value=""/>
[!] Default meta image, size recommended 1600x700 px

<Variable name="logo" description="Logo" type="string" value=""/>
[!] Schema logo, size recommended 175x55 px

<Variable name="favicon" description="Favicon" type="string" value=""/>
[!] Favicon high resolution, required format (.png), min size 200x200 px

<Variable name="analyticId" description="Analytic ID" type="string" value=""/>
[!] New Google Analytic 2021

<Variable name="caPubAdsense" description="caPubAdsense ID" type="string" value=""/> 
[!] number only

<Variable name="autoTOC" description="Table of content" type="string" value="true"/>
[!] true or false

<Variable name="positionTOC" description="Position TOC" type="string" value="noscript"/>
[!] tag name, class, id

<Variable name="maxLabel" description="Limit Label" type="string" value="3"/>
[!] Limit Label Display

-------------------------
#   Jettheme PageView   #
-------------------------

<Variable name="firebaseUrl" description="Firebase Url" type="string" value=""/>
[!] Page Views Use Firebase Realtime Database by url


-------------------------
#   Anti Boom Adsense   #
-------------------------

<Variable name="safeAds" description="Safe Adsense" type="string" value="false"/>
[!] true or false

<Variable name="limitAdsClick" description="limit Adsense User Click" type="string" value="3"/>
[!] Limit Adsense Clicks Per User, number


-------------------------
#   JetTheme SafeLink   #
-------------------------


<Variable name="safeLinkUrl" description="Safe Link Url" type="string" value="/"/>
[!] Set url go safelink page ( / ) = homepage, ( /p/safelink.html ) = SafeLink Page

<Variable name="safeLinkGenerate" description="Generate Url SafeLink" type="string" value=""/>
[!] tag name, class, id, ex : ( .safelink ) , ( #post-body a )

<Variable name="ignoreSafeLink" description="Ignore SafeLink Url" type="string" value=""/>
[!] Ignore Generate SafeLink, ex : ( blogger.com ) ( blogger.com,facebook.com )


-------------------------
# JetTheme Css Variable #
-------------------------

<Group description="_Main Color">
<Variable name="keycolor" description="Main Color" type="color" default="#0d6efd" value="#0d6efd"/>
<Variable name="body.background" description="Body Background Color" type="color" default="#ffffff" value="#ffffff"/>
<Variable name="body.text.color" description="Font Color" type="color" default="#686868" value="#686868"/>
<Variable name="posts.title.color" description="Heading Color" type="color" default="#343a40" value="#000000"/>
<Variable name="body.link.color" description="Link Color" type="color" default="$(keycolor)" value="#0d6efd"/>
<Variable name="body.hover.color" description="Link Hover" type="color" default="#0b5ed7" value="#0b5ed7"/>
<Variable name="border.color" description="Border Color" type="color" default="#efefef" value="#efefef"/>
<Variable name="posts.text.color" description="Blockquote Border Color" type="color" default="$(keycolor)" value="#0d6efd"/>
</Group>

<Group description="_Typography">
<Variable name="body.text" description="Body Font" type="font" default="normal normal 16px system-ui,-apple-system,Segoe UI,Helvetica Neue,Arial,Noto Sans,Liberation Sans,sans-serif,Apple Color Emoji,Segoe UI Emoji,Segoe UI Symbol,Noto Color Emoji" value="normal normal 16px system-ui,-apple-system,Segoe UI,Helvetica Neue,Arial,Noto Sans,Liberation Sans,sans-serif,Apple Color Emoji,Segoe UI Emoji,Segoe UI Symbol,Noto Color Emoji"/>
<Variable name="posts.title" description="Heading Font" type="font" default="normal bold 40px var(--bs-font-sans-serif)" value="normal bold 40px var(--bs-font-sans-serif)"/>
<Variable name="title.h2" description="H2 Size" type="length" default="26px" min="12px" max="50px" value="26px"/>
<Variable name="title.h3" description="H3 Size" type="length" default="22px" min="12px" max="50px" value="22px"/>
<Variable name="title.h4" description="H4 Size" type="length" default="20px" min="12px" max="50px" value="20px"/>
<Variable name="title.h5" description="H5 Size" type="length" default="18px" min="12px" max="50px" value="18px"/>
<Variable name="title.h6" description="H6 Size" type="length" default="16px" min="12px" max="50px" value="16px"/>
</Group> 

<Group description="_Logo">
<Variable name="logo.width" description="Logo Max Width" type="length" default="200px" min="50px" max="500px" value="200px"/>
<Variable name="logo.width.mobile" description="Logo Max Width (mobile)" type="length" default="150px" min="50px" max="500px" value="150px"/>
</Group>

<Group description="_Header Color">
<Variable name="header.bg" description="Background" type="color" default="#ffffff" value="#ffffff"/>
<Variable name="header.color" description="Font Color " type="color" default="#686868" value="#686868"/>
<Variable name="header.border" description="Border Color" type="color" default="#efefef" value="#efefef"/>
</Group>

<Group description="_Menu">
<Variable name="tabs.font" description="Menu Font" type="font" default="normal bold 16px var(--bs-font-sans-serif)" value="normal bold 16px var(--bs-font-sans-serif)"/>
<Variable name="tabs.color" description="Font Color" type="color" default="$(body.text.color)" value="#686868"/>
<Variable name="tabs.hover" description="Font Hover" type="color" default="$(keycolor)" value="#0d6efd"/>
<Variable name="tabs.selected.color" description="Font Selected" type="color" default="$(keycolor)" value="#0d6efd"/>
</Group>

<Group description="_Dropdown Menu">
<Variable name="dropdown.font" description="Font Size" type="length" default="16px" min="12px" max="50px" value="15px"/>
<Variable name="dropdown.bg" description="Background Color" type="color" default="$(body.text.color)" value="#ffffff"/>
<Variable name="dropdown.color" description="Font Color" type="color" default="$(keycolor)" value="#686868"/>
<Variable name="dropdown.hover" description="Font Hover" type="color" default="$(keycolor)" value="#f67938"/>
<Variable name="dropdown.selected" description="Dropdown Selected Color" type="color" default="$(keycolor)" value="#f67938"/>
</Group>

<Group description="_Footer Color">
<Variable name="footer.bg" description="Background Color" type="color" default="#212529" value="#212529"/>
<Variable name="footer.color" description="Font Color" type="color" default="#9fa6ad" value="#9fa6ad"/>
<Variable name="footer.link" description="Link Color" type="color" default="#9fa6ad" value="#9fa6ad"/>
<Variable name="footer.border" description="Border Color" type="color" default="#323539" value="#323539"/>
</Group>

<Group description="_Socket Color">
<Variable name="socket.bg" description="Background Color" type="color" default="#09080c" value="#09080c"/>
<Variable name="socket.color" description="Font Color" type="color" default="#9fa6ad" value="#9fa6ad"/>
</Group>

<Group description="_Button">
<Variable name="posts.icons.color" description="Button Color" type="color" default="$(keycolor)" value="#0d6efd"/>
<Variable name="labels.background.color" description="Button Hover"  type="color"  default="#0b5ed7" value="#0b5ed7"/>
</Group>

<Group description="_Comment Form">
<Variable name="body.text.font" description="Font" type="font" default="normal normal 14px system-ui,-apple-system,Segoe UI,Helvetica Neue,Arial,Noto Sans,Liberation Sans,sans-serif,Apple Color Emoji,Segoe UI Emoji,Segoe UI Symbol,Noto Color Emoji" value="normal normal 14px system-ui,-apple-system,Segoe UI,Helvetica Neue,Arial,Noto Sans,Liberation Sans,sans-serif,Apple Color Emoji,Segoe UI Emoji,Segoe UI Symbol,Noto Color Emoji"/>
<Variable name="posts.background.color" description="Background" type="color" default="transparent" value="rgba(0,0,0,0)"/>
</Group>
*/
/*
-----------------------------------------------
JetTheme Blogger Template
Name		: JetTheme Newspaper
Version		: 2.9
Designer	: jettheme
Provider    : SR7Themes
-----------------------------------------------
*/

:root{
--bs-font-sans-serif:$(body.text.family);
--bs-body-bg:$(body.background);
--bs-body-color:$(body.text.color);
--jt-primary:$(keycolor);
--jt-heading-color:$(posts.title.color);
--jt-heading-link:$(posts.title.color);
--jt-heading-hover:$(keycolor);
--jt-link-color:$(body.link.color);
--jt-link-hover:$(body.hover.color);
--jt-blockquote:$(posts.text.color);
--jt-btn-primary:$(posts.icons.color);
--jt-btn-primary-hover:$(labels.background.color);
--jt-btn-light-hover:$(posts.title.color);
--jt-border-light:$(border.color);
--jt-bg-light:#f3f7f9;
--jt-archive-bg:#fff;
--jt-nav-color:$(tabs.color);
--jt-nav-hover:$(tabs.hover);
--jt-nav-selected:$(tabs.selected.color);
--jt-dropdown-bg:$(dropdown.bg);
--jt-dropdown-color:$(dropdown.color);
--jt-dropdown-hover:$(dropdown.hover);
--jt-dropdown-selected:$(dropdown.selected);
--jt-header-bg:$(header.bg);
--jt-header-color:$(header.color);
--jt-header-border:$(header.border);
--jt-footer-bg:$(footer.bg);
--jt-footer-color:$(footer.color);
--jt-footer-link:$(footer.link);
--jt-footer-border:$(footer.border);
--jt-socket-bg:$(socket.bg);
--jt-socket-color:$(socket.color);
--jt-popup-bg:#fff
}
.dark-mode{
--bs-body-bg:hsl(210,11%,15%);
--bs-body-color:hsl(210,11%,80%);
--jt-heading-color:hsl(210,11%,80%);
--jt-heading-link:hsl(210,11%,80%);
--jt-btn-light-hover:hsl(210,11%,85%);
--jt-border-light:hsl(210,11%,20%);
--jt-bg-light:hsl(210,11%,20%);
--jt-archive-bg:hsl(210,11%,17%);
--jt-nav-color:hsl(210,11%,70%);
--jt-dropdown-bg:hsl(210,11%,18%);
--jt-dropdown-color:hsl(210,11%,70%);
--jt-header-bg:hsl(210,11%,15%);
--jt-header-color:hsl(210,11%,80%);
--jt-header-border:hsl(210,11%,20%);
--jt-footer-bg:hsl(210,11%,15%);
--jt-footer-color:hsl(210,11%,80%);
--jt-footer-border:hsl(210,11%,20%);
--jt-socket-bg:hsl(210,11%,17%);
--jt-socket-color:hsl(210,11%,80%);
--jt-popup-bg:hsl(210,11%,17%)
}
body{
font:$(body.text);
color:var(--bs-body-color);
background-color:var(--bs-body-bg);
line-height:1.5;
-webkit-font-smoothing:antialiased;
-moz-osx-font-smoothing:grayscale;
text-rendering:optimizeLegibility
}
.d-block{
display:none
}
.h1,.h2,.h3,.h4,.h5,.h6,h1,h2,h3,h4,h5,h6{
font:$(posts.title)
}
a{
transition-property:background-color,border-color,color,fill,stroke;
transition-timing-function:cubic-bezier(.4,0,.2,1);
transition-duration:.3s;
text-decoration:none;
color:var(--jt-link-color)
}
a:hover{
color:var(--jt-link-hover)
}
.fs-7{
font-size:.875rem
}
.fs-8{
font-size:.75rem
}
.fs-9{
font-size:.7rem
}
.btn{
box-shadow:none!important
}
.btn-sm{
min-width:32px;
min-height:32px
}
img,svg,iframe{
max-width:100%
}
img{
height:auto;
object-fit:cover
}
label{
cursor:pointer
}
.visually-hidden{
position:unset!important
}
.form-control:focus{
box-shadow:none;
border-color:var(--jt-primary)
}
.form-control::placeholder{
opacity:.5
}
.dropdown-toggle::after{
border-width:.25em .25em 0
}
.dropdown-menu{
margin:0;
padding:0
}
.px-3{
padding-right:1rem;
padding-left:1rem
}
.ratio:before{
content:none
}
.ratio-1x1{
padding-bottom:100%
}
.ratio-4x3{
padding-bottom:75%
}
.ratio-16x9{
padding-bottom:56.25%
}
.ratio-21x9{
padding-bottom:43%
}
.object-cover{
object-fit:cover
}
.max-w-80{
max-width:80%
}
.jt-text-primary,.hover-text-primary:hover,input:checked~.check-text-primary{
color:var(--jt-primary)!important
}
.jt-btn-primary,.jt-btn-outline-primary:hover{
color:#fff;
background-color:var(--jt-btn-primary);
border-color:var(--jt-btn-primary)
}
.jt-btn-light{
color:var(--bs-body-color);
background-color:var(--jt-bg-light);
border-color:var(--jt-bg-light)
}
.jt-btn-light:hover{
color:var(--jt-btn-light-hover)
}
.jt-btn-primary:hover,.hover-btn-primary:hover,input:checked+.jt-btn-outline-primary{
color:#fff!important;
background-color:var(--jt-btn-primary-hover)!important;
border-color:var(--jt-btn-primary-hover)!important
}
.jt-btn-outline-primary{
color:var(--jt-btn-primary);
border-color:var(--jt-btn-primary)
}
.jt-bg-primary{
background-color:var(--jt-primary)
}
.jt-bg-light{
background-color:var(--jt-bg-light)
}
.bg-archive{
background-color:var(--jt-archive-bg)
}
.jt-border-light{
border-color:var(--jt-border-light)!important
}
input:checked~.d-block-check{
display:block!important
}
input:checked~.d-none-check{
display:none!important
}
.dropdown-menu,.accordion-item,.accordion-header{
background-color:var(--bs-body-bg);
color:var(--bs-body-color);
border-color:var(--jt-border-light)
}
.lazyload{
transition-property:opacity;
transition-timing-function:cubic-bezier(.4,0,.2,1);
transition-duration:.3s;
opacity:0
}
.lazyload.loaded{
opacity:1
}
.cursor-default{
cursor:default!important
}
.drag-scroll{
cursor:grab
}
.drag-scroll.row>*{
scroll-snap-align:center
}
.drag-scroll.row>*{
max-width:80%
}
.drag-scroll.row-cols-2>*{
max-width:45%
}
pre{
background-color:var(--jt-bg-light);
margin-bottom:1rem;
padding:1rem;
font-size:.75rem
}
blockquote{
border-left:5px solid var(--jt-blockquote);
color:inherit;
font-size:1.125rem;
margin-bottom:1.5rem;
margin-top:1.5rem;
padding-left:1rem
}
/* ═══════════════════════════════════════════
   HEADER — The Treasure Notes
   Full responsive redesign with dark mode
   ═══════════════════════════════════════════ */

/* ---- Sticky header animate ---- */
.header-animate { transition: transform .3s cubic-bezier(.4,0,.2,1), box-shadow .3s; }
.header-animate.header-hidden { transform: translateY(-100%); box-shadow: none !important; }

/* ---- Header shell ---- */
#header {
  background-color: var(--jt-header-bg);
  color: var(--jt-header-color);
  border-bottom: 1px solid var(--jt-header-border);
  min-height: 56px;
  z-index: 9999;
  position: sticky;
  top: 0;
}

/* ---- Logo ---- */
.logo-img { height: 44px; width: auto; object-fit: contain; }
.tn-site-title {
  font-size: clamp(16px, 4vw, 22px);
  font-weight: 100;
  letter-spacing: 0.08em;
  color: var(--jt-heading-color) !important;
  text-decoration: none;
  white-space: nowrap;
}
.navbar-brand { padding: 0; margin-right: 0; }

/* ---- SVG icon base (Feather-style) ---- */
.jt-icon {
  display: inline-block;
  height: 1em;
  width: 1em;
  vertical-align: -.15em;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 2;
}
.jt-icon-center { font-family: sans-serif; }

/* ---- Header icon buttons ---- */
.tn-hdr-icon-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 38px;
  height: 38px;
  border-radius: 50%;
  cursor: pointer;
  color: var(--jt-header-color);
  transition: background .2s, color .2s;
  flex-shrink: 0;
}
.tn-hdr-icon-btn:hover {
  background: var(--jt-bg-light);
  color: var(--jt-primary);
}
.tn-hdr-icon-btn svg { font-size: 18px; }

/* ---- Social strip in header ---- */
.header-social { border-right: 1px solid var(--jt-header-border); }
.tn-header-border { border-color: var(--jt-header-border) !important; }

/* ---- Dark/Light icon logic ---- */
.icon-dark, .dark-mode .icon-light { display: none; }
.dark-mode .icon-dark { display: block; }

/* ---- Search dropdown ---- */
.tn-search-wrap { position: relative; }
.tn-search-dropdown {
  position: absolute;
  right: 0;
  top: calc(100% + 6px);
  min-width: 300px;
  background: var(--jt-dropdown-bg);
  border: 1px solid var(--jt-header-border);
  border-radius: 8px;
  padding: 10px 12px;
  z-index: 9999;
  box-shadow: 0 4px 20px rgba(0,0,0,.12);
  display: none;
}
#search-toggle:checked ~ .tn-search-dropdown { display: block; }
.tn-btn-search {
  background: var(--jt-primary);
  color: #fff;
  border: none;
  min-width: 40px;
}
.tn-btn-search:hover { background: var(--jt-btn-primary-hover); color: #fff; }

/* ---- Desktop navbar ---- */
.tn-navbar-collapse {
  display: flex !important;
  align-items: stretch;
}
.tn-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: stretch;
  flex-wrap: wrap;
}
.tn-nav-item {
  position: relative;
  display: flex;
  align-items: center;
}
.tn-nav-link {
  display: flex;
  align-items: center;
  padding: 0 14px;
  height: 100%;
  min-height: 56px;
  font-weight: 600;
  font-size: 14px;
  color: var(--jt-nav-color);
  text-decoration: none;
  white-space: nowrap;
  border-bottom: 2px solid transparent;
  transition: color .2s, border-color .2s;
}
.tn-nav-link:hover, .tn-nav-link.active {
  color: var(--jt-nav-hover);
  border-bottom-color: var(--jt-primary);
}

/* ---- Dropdown menus ---- */
.tn-dropdown-arrow {
  cursor: pointer;
  padding: 0 8px;
  font-size: 12px;
  color: var(--jt-nav-color);
}
.tn-dropdown-menu {
  position: absolute;
  top: 100%;
  left: 0;
  min-width: 180px;
  background: var(--jt-dropdown-bg);
  border: 1px solid var(--jt-header-border);
  border-radius: 6px;
  padding: 6px 0;
  box-shadow: 0 6px 20px rgba(0,0,0,.12);
  list-style: none;
  margin: 0;
  z-index: 9999;
  opacity: 0;
  visibility: hidden;
  transform: translateY(8px);
  transition: opacity .2s, transform .2s, visibility .2s;
}
.tn-nav-item:hover > .tn-dropdown-menu,
input:checked ~ .tn-dropdown-menu {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}
.tn-dropdown-menu .tn-nav-item { display: block; }
.tn-dropdown-menu .tn-nav-link {
  min-height: 36px;
  padding: 6px 16px;
  font-size: 13px;
  border-bottom: none;
  color: var(--jt-dropdown-color);
}
.tn-dropdown-menu .tn-nav-link:hover { color: var(--jt-dropdown-hover); background: var(--jt-bg-light); }

/* ---- Mobile close button ---- */
.tn-nav-close { display: none; }

/* ═══════════════════════════════════════════
   DESKTOP (≥992px)
   ═══════════════════════════════════════════ */
@media (min-width:992px) {
  #navbar-toggle, #navbar-toggle ~ * { }
  .tn-nav-close { display: none !important; }
}

/* ═══════════════════════════════════════════
   MOBILE (<992px)
   ═══════════════════════════════════════════ */
@media (max-width:991.98px) {
  .drag-scroll { overflow-x: auto !important; scroll-snap-type: x mandatory; }

  /* Mobile drawer */
  .tn-navbar-collapse {
    position: fixed;
    top: 0; left: 0; bottom: 0;
    width: min(300px, 85vw);
    background: var(--jt-header-bg);
    flex-direction: column;
    align-items: stretch;
    padding-top: 56px;
    overflow-y: auto;
    z-index: 9998;
    transform: translateX(-105%);
    transition: transform .32s cubic-bezier(.4,0,.2,1);
    box-shadow: 4px 0 20px rgba(0,0,0,.15);
  }
  /* Overlay backdrop */
  .tn-navbar-collapse::before {
    content: '';
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,.45);
    z-index: -1;
    opacity: 0;
    transition: opacity .32s;
    pointer-events: none;
  }
  #navbar-toggle:checked ~ * .tn-navbar-collapse,
  .tn-navbar-collapse.show {
    transform: translateX(0);
  }
  #navbar-toggle:checked ~ * .tn-navbar-collapse::before,
  .tn-navbar-collapse.show::before {
    opacity: 1;
    pointer-events: auto;
  }

  /* Mobile close X button */
  .tn-nav-close {
    display: flex;
    align-items: center;
    justify-content: center;
    position: absolute;
    top: 10px;
    right: 12px;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    cursor: pointer;
    color: var(--jt-header-color);
    background: var(--jt-bg-light);
    z-index: 1;
  }
  .tn-nav-close:hover { background: var(--jt-border-light); }

  /* Mobile nav list */
  .tn-nav-list { flex-direction: column; flex-wrap: nowrap; }
  .tn-nav-item { display: block; }
  .tn-nav-link {
    min-height: 48px;
    padding: 0 20px;
    font-size: 15px;
    border-bottom: 1px solid var(--jt-header-border);
    border-left: none;
  }
  .tn-nav-link:hover, .tn-nav-link.active {
    border-bottom-color: var(--jt-header-border);
    border-left: 3px solid var(--jt-primary);
    padding-left: 17px;
  }

  /* Mobile dropdown */
  .tn-dropdown-menu {
    position: static;
    box-shadow: none;
    border: none;
    border-radius: 0;
    padding: 0 0 0 16px;
    opacity: 1;
    visibility: visible;
    transform: none;
    display: none;
    background: var(--jt-bg-light);
  }
  input:checked ~ .tn-dropdown-menu { display: block; }
  .tn-dropdown-arrow {
    position: absolute;
    right: 0;
    top: 0;
    height: 48px;
    width: 48px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-left: 1px solid var(--jt-header-border);
  }
  input:checked + .tn-dropdown-arrow svg { transform: rotate(180deg); }
  .tn-dropdown-arrow svg { transition: transform .2s; }

  /* Search full-width on mobile */
  .tn-search-dropdown {
    position: fixed;
    left: 0; right: 0;
    top: 56px;
    min-width: unset;
    border-radius: 0;
    border-left: none;
    border-right: none;
    border-top: none;
  }

  .logo-wrap { max-width: 150px; }
  #sidebar { border-top: 1px solid var(--jt-border-light); }
}

@media (max-width:575.98px) {
  #post-pager .prev-page + .next-page { border-top: 1px solid; }
  .full-width, .px-3 .google-auto-placed { margin-left: -1rem; margin-right: -1rem; width: auto !important; }
  #footer-widget .widget { padding-left: 3rem; padding-right: 3rem; }
}

/*Your custom CSS is here*/

/* ===== The Treasure Notes — Site title font ===== */
.tn-site-title {
  font-family: 'Roboto', system-ui, sans-serif;
  font-weight: 100;
  font-size: clamp(17px, 3.5vw, 22px);
  letter-spacing: 0.06em;
  color: var(--jt-heading-color) !important;
  text-decoration: none;
  line-height: 1.2;
}
.dark-mode .tn-site-title { color: var(--jt-heading-color) !important; }

/* ── Logo + site-name layout ── */
.logo-wrap { display: flex; align-items: center; }

/* ── Header container height ── */
#header .container { min-height: 56px; display: flex; align-items: center; }

/* ── Active nav indicator ── */
.tn-nav-link.active { color: var(--jt-primary) !important; }

/* ── Prevent icon flash before SVG loads ── */
.jt-icon use { pointer-events: none; }

/* ── Dark-mode meta tag color ── */
@media (prefers-color-scheme:dark) {
  :root:not(.dark-mode) { color-scheme: light; }
}


/* ===== The Treasure Notes - Custom UI ===== */

/* --- Navigation Quick-Link Buttons (matching screenshot) --- */
.tn-nav-section {
  margin-bottom: 1.5rem;
}
.tn-section-label {
  text-align: center;
  font-weight: 700;
  font-size: 13px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  padding: 6px 0;
  margin-bottom: 8px;
  color: #fff;
  background: #222;
  border-radius: 4px;
}
.tn-btn-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 6px;
  margin-bottom: 8px;
}
.tn-btn-grid.cols-2 { grid-template-columns: repeat(2, 1fr); }
.tn-btn-grid.cols-4 { grid-template-columns: repeat(4, 1fr); }
.tn-nav-btn {
  display: block;
  text-align: center;
  padding: 9px 8px;
  font-size: 13px;
  font-weight: 600;
  border-radius: 4px;
  color: #fff !important;
  text-decoration: none;
  transition: opacity .2s;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.tn-nav-btn:hover { opacity: 0.85; color: #fff !important; }
.tn-btn-black  { background: #1a1a1a; }
.tn-btn-blue   { background: #1565C0; }
.tn-btn-dblue  { background: #0d47a1; }
.tn-btn-lblue  { background: #1976D2; }
.tn-btn-green  { background: #2e7d32; }
.tn-btn-lgreen { background: #388e3c; }
.tn-btn-teal   { background: #00695c; }
.tn-btn-lteal  { background: #00897b; }
.tn-btn-orange { background: #e65100; }
.tn-btn-lorange{ background: #f57c00; }
.tn-btn-red    { background: #c62828; }
.tn-btn-lred   { background: #d32f2f; }
.tn-btn-purple { background: #6a1b9a; }
.tn-btn-lpurple{ background: #7b1fa2; }
.tn-btn-indigo { background: #283593; }
.tn-btn-pink   { background: #ad1457; }
.tn-btn-brown  { background: #4e342e; }
.tn-btn-cyan   { background: #00838f; }
.tn-btn-yellow { background: #f9a825; color: #333 !important; }

/* Responsive: 2 cols on mobile for some grids */
@media (max-width: 576px) {
  .tn-btn-grid { grid-template-columns: repeat(2, 1fr); }
  .tn-btn-grid.cols-4 { grid-template-columns: repeat(2, 1fr); }
}

/* --- Header tweaks --- */
#header {
  box-shadow: 0 1px 4px rgba(0,0,0,.1);
}

/* --- Trending Posts sidebar title style --- */
#sidebar .widget-title {
  font-size: 14px !important;
  font-weight: 700;
  letter-spacing: 0.3px;
}

/* --- Published badge color --- */
.badge.bg-success, .badge-published {
  background-color: #1565C0 !important;
}

/* --- Widget title bar underline accent --- */
#main .widget-title:before {
  border-right-color: #0d6efd;
}
#footer .widget-title:after {
  border-color: #0d6efd;
}

