/**/
(function(){
  /* Dark-mode toggle */
  var html = document.querySelector('html');
  var toggler = document.getElementById('dark-toggler');
  if(toggler){
    toggler.addEventListener('click',function(){
      if(html.classList.contains('dark-mode')){
        html.classList.remove('dark-mode');
        try{localStorage.setItem('theme','light');}catch(e){}
      }else{
        html.classList.add('dark-mode');
        try{localStorage.setItem('theme','dark');}catch(e){}
      }
    });
  }

  /* Navbar mobile toggle */
  var navToggle = document.getElementById('navbar-toggle');
  var navbar = document.getElementById('navbar');
  if(navToggle && navbar){
    navToggle.addEventListener('change',function(){
      if(navToggle.checked){
        navbar.classList.add('show');
        document.body.style.overflow='hidden';
      }else{
        navbar.classList.remove('show');
        document.body.style.overflow='';
      }
    });
    document.addEventListener('click',function(e){
      if(navToggle.checked && !navbar.contains(e.target) && e.target!==navToggle){
        navToggle.checked=false;
        navbar.classList.remove('show');
        document.body.style.overflow='';
      }
    });
  }

  /* Sticky header hide-on-scroll */
  var header = document.getElementById('header');
  var lastScroll = 0;
  window.addEventListener('scroll',function(){
    var cur = window.pageYOffset||document.documentElement.scrollTop;
    if(header){
      if(cur>lastScroll && cur>80) header.classList.add('header-hidden');
      else header.classList.remove('header-hidden');
    }
    lastScroll = cur<=0?0:cur;
  },{passive:true});

  /* Date formatter */
  document.querySelectorAll('.date-format').forEach(function(el){
    var iso=el.getAttribute('data-date');
    if(iso){try{var d=new Date(iso);el.textContent=d.toLocaleDateString('en-IN',{year:'numeric',month:'short',day:'numeric'});}catch(e){}}
  });
})();
/**/
